```cpp
#include <iostream>
using namespace std;

/**
 * @brief 再帰的にn番目のフィボナッチ数を計算する関数
 * @param n フィボナッチ数のインデックス（0以上の非負整数）
 * @return n番目のフィボナッチ数、負の入力の場合は-1を返しエラーメッセージを出力
 */
long long fibonacci(int n) {
    // 負のインデックスには対応しない
    if (n < 0) {
        cerr << "エラー: フィボナッチ数列は負の整数には定義されません" << endl;
        return -1;
    }
    // 再帰の基底部（ベースケース）
    if (n == 0) return 0;
    if (n == 1) return 1;
    // 再帰的に問題を分割して解く
    return fibonacci(n - 1) + fibonacci(n - 2);
}

int main() {
    int input_num;
    cout << "===== 再帰版フィボナッチ計算プログラム =====" << endl;
    cout << "求めたいフィボナッチ数のインデックスを入力してください: ";

    // 不正な入力をチェック
    if (!(cin >> input_num)) {
        cerr << "エラー: 有効な整数を入力してください" << endl;
        return 1;
    }

    long long result = fibonacci(input_num);
    // エラーがない場合のみ結果を出力
    if (result != -1 && input_num >= 0) {
        cout << input_num << "番目のフィボナッチ数は " << result << " です" << endl;
    }

    return 0;
}
```

